(function(w){"use strict";
function e(v){return String(v==null?"":v).replace(/[&<>"']/g,function(c){return {"&":"&amp;","<":"&lt;",">":"&gt;","\"":"&quot;","'":"&#39;"}[c]||c;});}
function renderField(f){var a=' data-key="'+e(f.key)+'"';if(f.raw)a+=' data-raw="1"';if(f.type==='select'){return '<div class="hm-calc-field"><label>'+e(f.label)+'</label><select class="hm-calc-select"'+a+'>'+f.options.map(function(o){return '<option value="'+e(o[0])+'"'+(String(o[0])===String(f.default)?' selected':'')+'>'+e(o[1])+'</option>';}).join('')+'</select></div>';}if(f.type==='textarea'){return '<div class="hm-calc-field"><label>'+e(f.label)+'</label><textarea class="hm-calc-input" rows="4"'+a+' placeholder="'+e(f.placeholder||'')+'">'+e(f.default||'')+'</textarea></div>';}var type=f.type==='date'?'date':'text';var mode=f.type==='integer'?'numeric':'decimal';return '<div class="hm-calc-field"><label>'+e(f.label)+'</label><input class="hm-calc-input" type="'+type+'" inputmode="'+mode+'"'+a+' placeholder="'+e(f.placeholder||'')+'" value="'+e(f.default||'')+'"></div>';}
function makeRender(def){return function(root,api){var html='<div class="hm-calc-panel"><div class="hm-calc-form">';if(def.hint)html+='<p class="hm-calc-hint">'+e(def.hint)+'</p>';html+='<div class="hm-calc-grid-2">'+def.fields.map(renderField).join('')+'</div><div class="hm-calc-actions"><button type="button" class="hm-calc-btn">계산하기</button></div><p class="hm-calc-message" hidden></p></div><div class="hm-calc-result" hidden></div></div>';root.innerHTML=html;var els=Array.prototype.slice.call(root.querySelectorAll('[data-key]')),go=root.querySelector('button'),msg=root.querySelector('.hm-calc-message'),res=root.querySelector('.hm-calc-result');go.addEventListener('click',function(){var x={};els.forEach(function(el){var k=el.getAttribute('data-key');if(el.tagName==='SELECT'||el.getAttribute('data-raw')==='1'||el.type==='date')x[k]=el.value;else x[k]=api.parseNumber(el.value);});var r=def.compute(x);if(r&&r.error){api.setMessage(msg,r.error);api.clearResult(res);return;}api.setMessage(msg,'');api.setResult(res,def.format(r,api));});};}
var defs=[{id:"paint-quantity",fields:[{"key":"area","label":"도장 면적 (㎡)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"coverage","label":"1L당 도포면적 (㎡)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"coats","label":"도장 횟수","type":"integer","placeholder":"","default":"2","options":[],"raw":false},{"key":"waste","label":"여유율 (%)","type":"number","placeholder":"","default":"10","options":[],"raw":false},{"key":"canSize","label":"페인트 한 통 용량 (L)","type":"number","placeholder":"","default":"4","options":[],"raw":false}],hint:"제품별 실제 도포면적과 바탕 상태에 따라 사용량이 달라질 수 있습니다.",compute:function(x){var a=Number(x.area),c=Number(x.coverage),n=Number(x.coats),w=Number(x.waste)/100,s=Number(x.canSize);if(![a,c,n,w,s].every(Number.isFinite)||a<0||c<=0||!Number.isInteger(n)||n<=0||w<0||s<=0)return{error:"도포면적과 통 용량은 0보다 크고 도장 횟수는 1 이상의 정수여야 합니다."};var liters=a*n/c*(1+w);return{liters:liters,cans:Math.ceil(liters/s)};},format:function(r,api){return api.resultCard("필요 페인트",api.formatNumber(r.liters,4)+"L","")+api.resultCard("구매 권장 수량",api.formatNumber(r.cans,0)+"통","");}},{id:"wallpaper-rolls",fields:[{"key":"area","label":"시공 면적 (㎡)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"coveragePerRoll","label":"롤당 실사용 면적 (㎡)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"waste","label":"여유율 (%)","type":"number","placeholder":"","default":"10","options":[],"raw":false}],hint:"무늬 맞춤과 창문·문 위치에 따라 추가 여유분이 필요할 수 있습니다.",compute:function(x){var a=Number(x.area),c=Number(x.coveragePerRoll),w=Number(x.waste)/100;if(![a,c,w].every(Number.isFinite)||a<0||c<=0||w<0)return{error:"롤당 실사용 면적은 0보다 커야 합니다."};var needed=a*(1+w);return{adjustedArea:needed,rolls:Math.ceil(needed/c)};},format:function(r,api){return api.resultCard("필요 벽지",api.formatNumber(r.rolls,0)+"롤","")+api.resultCard("여유율 포함 면적",api.formatNumber(r.adjustedArea,4)+"㎡","");}},{id:"tile-quantity",fields:[{"key":"area","label":"시공 면적 (㎡)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"tileWidth","label":"타일 가로 (cm)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"tileHeight","label":"타일 세로 (cm)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"waste","label":"여유율 (%)","type":"number","placeholder":"","default":"10","options":[],"raw":false}],hint:"",compute:function(x){var a=Number(x.area),w=Number(x.tileWidth),h=Number(x.tileHeight),p=Number(x.waste)/100;if(![a,w,h,p].every(Number.isFinite)||a<0||w<=0||h<=0||p<0)return{error:"타일 가로·세로는 0보다 커야 합니다."};var each=w*h/10000,raw=a/each,need=raw*(1+p);return{tileArea:each,rawCount:raw,count:Math.ceil(need)};},format:function(r,api){return api.resultCard("구매 권장 수량",api.formatNumber(r.count,0)+"장","")+api.resultCard("여유율 제외 필요량",api.formatNumber(r.rawCount,4)+"장","");}},{id:"flooring-packs",fields:[{"key":"area","label":"시공 면적 (㎡)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"coveragePerPack","label":"한 포장 시공면적 (㎡)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"waste","label":"여유율 (%)","type":"number","placeholder":"","default":"8","options":[],"raw":false}],hint:"",compute:function(x){var a=Number(x.area),c=Number(x.coveragePerPack),w=Number(x.waste)/100;if(![a,c,w].every(Number.isFinite)||a<0||c<=0||w<0)return{error:"포장당 시공면적은 0보다 커야 합니다."};var adjusted=a*(1+w);return{adjustedArea:adjusted,packs:Math.ceil(adjusted/c)};},format:function(r,api){return api.resultCard("필요 포장 수",api.formatNumber(r.packs,0)+"개","")+api.resultCard("여유율 포함 면적",api.formatNumber(r.adjustedArea,4)+"㎡","");}},{id:"concrete-volume",fields:[{"key":"length","label":"길이 (m)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"width","label":"너비 (m)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"thickness","label":"두께 (cm)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"waste","label":"여유율 (%)","type":"number","placeholder":"","default":"5","options":[],"raw":false}],hint:"현장 손실과 배합·타설 조건에 따라 실제 주문량은 달라질 수 있습니다.",compute:function(x){var l=Number(x.length),w=Number(x.width),t=Number(x.thickness),p=Number(x.waste)/100;if(![l,w,t,p].every(Number.isFinite)||l<0||w<0||t<0||p<0)return{error:"입력값은 0 이상이어야 합니다."};var base=l*w*t/100,total=base*(1+p);return{base:base,total:total,liters:total*1000};},format:function(r,api){return api.resultCard("여유율 포함 필요량",api.formatNumber(r.total,6)+"㎥","")+api.resultCard("리터 환산",api.formatNumber(r.liters,2)+"L","");}},{id:"moving-box-volume",fields:[{"key":"length","label":"상자 가로 (cm)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"width","label":"상자 세로 (cm)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"height","label":"상자 높이 (cm)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"quantity","label":"상자 수량","type":"integer","placeholder":"","default":"1","options":[],"raw":false}],hint:"",compute:function(x){var l=Number(x.length),w=Number(x.width),h=Number(x.height),q=Number(x.quantity);if(![l,w,h,q].every(Number.isFinite)||l<0||w<0||h<0||!Number.isInteger(q)||q<=0)return{error:"상자 수량은 1 이상의 정수여야 합니다."};var one=l*w*h/1000,total=one*q;return{oneLiters:one,totalLiters:total,totalM3:total/1000};},format:function(r,api){return api.resultCard("전체 부피",api.formatNumber(r.totalM3,6)+"㎥","")+api.resultCard("리터 환산",api.formatNumber(r.totalLiters,2)+"L","")+api.resultCard("상자 1개",api.formatNumber(r.oneLiters,2)+"L","");}}];defs.forEach(function(def){w.HM_CALC.register(def.id,{compute:def.compute,render:makeRender(def)});});})(window);
